    let result = shorten_text(&source_data);
    println!("Result: {}", result);
}

// This function signature demonstrates the need for explicit lifetime management 
// when returning a reference derived from an input reference.
fn shorten_text<'a>(input: &'a String) -> &'a str {
    let original_slice = input.as_str();
    if original_slice.len() < 10 {
        return original_slice;
    }
    // We return a slice that is guaranteed to live at least as long as the input reference.
    &original_slice[..10]
}
